WITH mask_counts AS (
    SELECT mask, COUNT(*) AS cnt FROM field_rules GROUP BY mask
),
global_avg AS (
    SELECT AVG(cnt) AS avg_cnt FROM mask_counts
),
ruleset_mask_counts AS (
    SELECT ruleset_id, mask, COUNT(*) AS cnt FROM field_rules GROUP BY ruleset_id, mask
),
ruleset_avg AS (
    SELECT ruleset_id, AVG(cnt) AS avg_cnt FROM ruleset_mask_counts GROUP BY ruleset_id
)
SELECT r.ruleset_id, r.avg_cnt, g.avg_cnt,
       (r.avg_cnt / g.avg_cnt) * 100.0 AS percent_of_global
FROM ruleset_avg r, global_avg g
WHERE (r.avg_cnt / g.avg_cnt) < 0.8;

WITH total_masks AS (
  SELECT COUNT(DISTINCT mask) AS total FROM documents
),
covered_masks AS (
  SELECT COUNT(DISTINCT mask) AS covered FROM field_rules
)
SELECT (covered * 1.0 / total) AS proportion_masks_covered
FROM total_masks, covered_masks;

SELECT AVG(cnt) AS avg_field_rules_per_mask
FROM (
  SELECT fr.mask, COUNT(*) AS cnt
  FROM field_rules fr
  GROUP BY fr.mask
);

SELECT COUNT(DISTINCT ruleset_id) AS nb_rulesets
FROM validation_rules
WHERE mask = 'M57_CFU';

SELECT AVG(cnt) AS avg_rules_per_ruleset
FROM (
    SELECT ruleset_id, COUNT(*) AS cnt
    FROM field_rules
    GROUP BY ruleset_id
) sub;

SELECT AVG(d.nb_pages) AS avg_pages
FROM documents d
WHERE d.budget_type = 'BA' AND d.document_year = '2023';

WITH total_masks AS (
    SELECT COUNT(DISTINCT mask) AS cnt FROM documents
),
covered_masks AS (
    SELECT COUNT(DISTINCT mask) AS cnt FROM field_rules
)
SELECT (covered_masks.cnt * 100.0 / total_masks.cnt) AS coverage_percent
FROM total_masks, covered_masks;

SELECT COUNT(DISTINCT er.document_id) AS docs_with_errors
FROM extraction_results er
WHERE er.message_error IS NOT NULL AND er.message_error <> '';

SELECT COUNT(*) AS docs_without_results
FROM documents d
WHERE d.document_year = '2024'
  AND NOT EXISTS (
      SELECT 1 FROM extraction_results er WHERE er.document_id = d.document_id
  );

SELECT COUNT(DISTINCT city_name) AS nb_municipalities_2024
FROM documents
WHERE document_year = '2024';

SELECT COUNT(DISTINCT r.value) AS distinct_years
FROM extraction_results r
WHERE r.safir_field_id = 'Année';

SELECT COUNT(DISTINCT d.city_name) AS muni_count
FROM documents d
WHERE d.mask = 'M57_CA';

WITH docs_with_error AS (
  SELECT DISTINCT document_id
  FROM extraction_results
  WHERE message_error IS NOT NULL AND TRIM(message_error) <> ''
)
SELECT (SELECT COUNT(*) FROM docs_with_error) * 100.0 / (SELECT COUNT(*) FROM documents) AS pct_documents_avec_erreur;

SELECT AVG(nb_pages) AS avg_pages
FROM documents
WHERE budget_type = 'BP' AND document_year = '2024';

SELECT COUNT(DISTINCT d.city_name) AS municipalities_with_error
FROM documents d
WHERE d.document_year = '2024' AND d.error_message <> '';
